<?php header('Content-Type: application/json; '); $iniFile = __DIR__ . '/../conf/conf.ini'; $config = parse_ini_file($iniFile, true); $AdUser = $config['AdGuard']['user'] ?? 'unknown'; $AdPass = $config['AdGuard']['pass'] ?? 'unknown'; $AdUrl = $config['AdGuard']['url'] ?? 'unknown'; $ImmUrl = $config['Immich']['url'] ?? 'unknown'; function getCpuTemp() { foreach (glob('/sys/class/hwmon/hwmon*/name') as $file) { if (trim(file_get_contents($file)) === 'coretemp') { $dir = dirname($file); $temp = file_get_contents($dir . '/temp1_input'); return round($temp / 1000, 1); } } return "unauthorized"; }function getAcpiTemp() { foreach (glob('/sys/class/thermal/thermal_zone*/type') as $file) { $type = @file_get_contents($file); if ($type === false) continue; if (strpos(strtolower($type), 'acpi') !== false) { $zone = dirname($file) . '/temp'; if (is_readable($zone)) { $temp = @file_get_contents($zone); if ($temp !== false && is_numeric($temp)) { return round($temp / 1000, 1); } } } } return "unauthorized"; }function getCpuUsagePerCore($delay=1){ $stat1 = file('/proc/stat'); usleep($delay*1000000); $stat2 = file('/proc/stat'); $cpus = []; foreach ($stat1 as $i=>$line) { if (strpos($line, 'cpu') !== 0 || strpos($line, 'cpu ') === 0) continue; $parts1 = preg_split('/\s+/', trim($line)); $parts2 = preg_split('/\s+/', trim($stat2[$i])); $idle1 = $parts1[4]; $idle2 = $parts2[4]; $total1 = array_sum(array_slice($parts1,1,7)); $total2 = array_sum(array_slice($parts2,1,7)); $totalDiff = $total2 - $total1; $idleDiff = $idle2 - $idle1; $usage = $totalDiff > 0 ? (100*($totalDiff-$idleDiff)/$totalDiff) : 0; $cpus[] = round($usage,1); } return $cpus; } function getAdGuardStatus() { global $AdUrl; global $AdUser; global $AdPass; $url = $AdUrl . "/control/stats"; $user = $AdUser; $pass = $AdPass; $ch = curl_init($url); curl_setopt_array($ch, [ CURLOPT_RETURNTRANSFER => true, CURLOPT_USERPWD => "$user:$pass", CURLOPT_HTTPAUTH => CURLAUTH_BASIC, CURLOPT_TIMEOUT => 5 ]); $response = curl_exec($ch); $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE); curl_close($ch); if($httpCode !== 200 || !$response) { return [ "running" => false, "dns_queries" => 0, "blocked" => 0, "allowed" => 0 ]; } $data = json_decode($response,true); $queries = $data['num_dns_queries'] ?? 0; $blocked = $data['num_blocked_filtering'] ?? 0; $allowed = $queries - $blocked; return [ "running" => true, "dns_queries" => $queries, "blocked" => $blocked, "allowed" => $allowed ]; } function getServerInfo() { $load = sys_getloadavg(); $load = [ round($load[0],2), round($load[1],2), round($load[2],2) ]; $meminfo = file("/proc/meminfo"); $memTotal = $memAvailable = 0; $swapTotal = $swapFree = 0; foreach ($meminfo as $line) { if (strpos($line, "MemTotal:") === 0) $memTotal = (int) filter_var($line, FILTER_SANITIZE_NUMBER_INT); if (strpos($line, "MemAvailable:") === 0) $memAvailable = (int) filter_var($line, FILTER_SANITIZE_NUMBER_INT); if (strpos($line, "SwapTotal:") === 0) $swapTotal = (int) filter_var($line, FILTER_SANITIZE_NUMBER_INT); if (strpos($line, "SwapFree:") === 0) $swapFree = (int) filter_var($line, FILTER_SANITIZE_NUMBER_INT); } $memUsed = $memTotal - $memAvailable; $swapUsed = $swapTotal - $swapFree; function isImmichRunning() { global $ImmUrl; $url = $ImmUrl . "/api/server/ping"; $ch = curl_init($url); curl_setopt_array($ch, [ CURLOPT_RETURNTRANSFER => true, CURLOPT_TIMEOUT => 3 ]); $res = curl_exec($ch); $http = curl_getinfo($ch, CURLINFO_HTTP_CODE); curl_close($ch); return ($res && $http === 200); } function getUptime() { if (!is_readable("/proc/uptime")) return null; $uptime = floatval(explode(" ", file_get_contents("/proc/uptime"))[0]); $days = floor($uptime/86400); $hours = floor(($uptime%86400)/3600); $minutes = floor(($uptime%3600)/60); return "$days d $hours h $minutes m"; } return [ "uptime"=>getUptime(), "acpi_temp"=>getAcpiTemp(), "immich"=>["running"=>isImmichRunning()], "cpu"=>[ "load"=>$load, "temp"=>getCpuTemp(), "per_core"=>getCpuUsagePerCore(1) ], "memory"=>[ "total"=>$memTotal*1024, "used"=>$memUsed*1024, "free"=>$memAvailable*1024 ], "swap"=>[ "total"=>$swapTotal*1024, "used"=>$swapUsed*1024, "free"=>$swapFree*1024 ], "adguard"=>getAdGuardStatus() ]; } echo json_encode(getServerInfo()); 
